module RefModule (
    input clk,
    input reset,
    input up_down,
    output [3:0] count );reg [3:0] obf_count_reg;

always @(posedge clk) begin
    if (reset)
        obf_count_reg <= 4'b0000;
    else if (up_down)
        obf_count_reg <= obf_count_reg + 1;
    else
        obf_count_reg <= obf_count_reg - 1;
end

assign count = obf_count_reg;

endmodule
